import pymongo, datetime
from bson import json_util
from bson.objectid import ObjectId
from bson.json_util import dumps as dumps2
from flask import Flask, make_response, request, Response

import os


class Mongo(object):
    def __init__(self, url=os.environ['MONGODB_URI']):
        self._client = pymongo.MongoClient(url)
        self._db = self._client[os.path.split(url)[1].lstrip('//')]

    def query(self, collname):  # a MongoDB collection name with the same syntax as in $query
        return self._db[collname]


def mongo_query(collname):
    return Mongo().query(collname)


app = Flask(__name__)


@app.route('/filter', methods=['POST'])
def filter():
    """Given a JSON query, returns documents where the provided query evaluates to True."""
    try:
        query = request.json
        resp_list = []

        # Get data from Mongo DB, return it to user as json in the end.
        for collname in query["collection"]:
            data = mongo_query(collname).find()

            for document in data:
                # Use $where operator and eval expression on server side.
                result = list(mongo_query('result').insert({
                    "$where": str(query['expression']),
                    "field": dumps2(document)
                }))

                # Add result to response
                resp_list += [{"collectionname": collname,
                               'data': result}]

        return Response([dumps({'result': resp}) for resp in resp_list],
                        mimetype='application/json')

    except Exception as ex:
        print(ex)


if __name__ == '__main__':
    app.run(debug=True)